def f(n: int) -> int:
    """Return the n‑th prime (1‑based, f(1) == 2). Supports n up to at least 100."""
    if n < 1:
        raise ValueError("n must be a positive integer")
    # Simple trial‑division sieve – more than enough for the first 100 primes
    primes = []
    candidate = 2
    while len(primes) < n:
        is_prime = True
        limit = int(candidate ** 0.5) + 1
        for p in primes:
            if p > limit:
                break
            if candidate % p == 0:
                is_prime = False
                break
        if is_prime:
            primes.append(candidate)
        candidate += 1 if candidate == 2 else 2  # after 2, check only odd numbers
    return primes[-1]
```

